const fs = require('fs');
const path = require('path');

// Hex-encoded project files dictionary (100% immune to platform proxy-rewriting or character mangling)
const FILES = {
  "package.json": "",
  "vite.config.ts": "",
  "tsconfig.json": "",
  "index.html": "",
  ".gitignore": "6e6f64655f6d6f64756c65732f0a6275696c642f0a646973742f0a636f7665726167652f0a2e44535f53746f72650a2a2e6c6f670a2e656e762a0a212e656e762e6578616d706c650a",
  "src/main.tsx": "",
  "src/index.css": "40696d706f727420227461696c77696e64637373223b0a",
  "src/types.ts": "",
  "src/initialData.ts": "",
  "src/excelUtils.ts": "",
  "src/App.tsx": ""
};

console.log('🚀 Iniciando instalación de estructura del proyecto local...');

for (const [relPath, hexContent] of Object.entries(FILES)) {
  const fullPath = path.resolve(relPath);
  const dirPath = path.dirname(fullPath);

  // Crear directorios de forma recursiva si no existen
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
    console.log('📁 Carpeta creada:', path.relative(process.cwd(), dirPath) || '.');
  }

  // Decodificar Hex y escribir el archivo
  const fileBuffer = Buffer.from(hexContent, 'hex');
  fs.writeFileSync(fullPath, fileBuffer);
  console.log('📄 Archivo creado:', relPath);
}

console.log('\n✅ ¡Proyecto de Crianza recreado exitosamente de forma local!');
console.log('------------------------------------------------------------');
console.log('Para iniciar tu proyecto:');
console.log('  1. Abre VS Code en esta carpeta ("presupuesto-crianza").');
console.log('  2. Ejecuta en la terminal de VS Code:');
console.log('     npm install');
console.log('  3. Inicia el servidor de desarrollo local:');
console.log('     npm run dev');
console.log('------------------------------------------------------------\n');
